DROP TABLE IF EXISTS `shift_monthly_templates`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `shift_monthly_templates` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(160) COLLATE utf8mb4_unicode_ci NOT NULL,
  `division_id` int unsigned NOT NULL,
  `target_month` date NOT NULL,
  `status` enum('draft','previewed','applied','archived') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'draft',
  `settings_json` json NOT NULL,
  `created_by` int unsigned NOT NULL,
  `updated_by` int unsigned NOT NULL,
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `archived_at` datetime DEFAULT NULL,
  `applied_at` datetime DEFAULT NULL,
  `applied_by` int unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_shift_monthly_templates_month` (`target_month`,`status`),
  KEY `idx_shift_monthly_templates_division` (`division_id`,`target_month`),
  CONSTRAINT `fk_shift_monthly_templates_division` FOREIGN KEY (`division_id`) REFERENCES `tracs_divisions` (`id`) ON DELETE RESTRICT ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

