INSERT INTO `tracs_cases` VALUES (1,1,1,NULL,'Login issue on email portal','User cannot login intermittently on email system','completed','high','2026-05-08 20:32:00','2026-05-08 18:32:47','2026-05-19 12:35:51'),(2,1,1,NULL,'Domain transfer stuck verification','Domain stuck at registrar approval stage','completed','high','2026-05-08 23:32:47','2026-05-08 18:32:47','2026-06-08 11:05:25'),(3,1,1,NULL,'SSL renewal request','SSL renewal completed but not propagated','completed','medium','2026-05-09 18:32:47','2026-05-08 18:32:47','2026-05-08 18:32:47'),(4,1,1,NULL,'Payment gateway timeout error','','completed','critical','2026-05-08 19:02:00','2026-05-08 18:32:47','2026-05-15 20:03:21'),(5,1,1,NULL,'Email login delay issue login.masuk.email','','completed','critical','2026-05-08 18:47:00','2026-05-08 18:32:47','2026-05-16 13:35:57'),(6,1,1,NULL,'Payment gateway timeout on checkout API','Random timeout detected during callback validation from Midtrans.','on_hold','critical','2026-05-08 20:43:11','2026-05-08 18:26:11','2026-06-08 15:36:03'),(7,1,1,NULL,'SMTP login latency on login.masuk.email','High response time reported from Jakarta region.','stuck','critical','2026-05-08 21:06:11','2026-05-08 16:26:11','2026-06-08 15:36:05'),(8,1,1,NULL,'Domain transfer pending registry approval','Waiting manual approval from registrar.','completed','high','2026-05-08 23:26:11','2026-05-06 20:26:11','2026-06-13 14:45:37'),(9,1,1,NULL,'SSL auto renewal failed for client node','LetsEncrypt renewal hook returned invalid challenge.','active','high','2026-05-09 01:26:11','2026-05-07 20:26:11','2026-05-08 20:26:11'),(10,1,1,NULL,'DNS propagation mismatch Cloudflare','Several NS still resolving old IP.','pending','medium','2026-05-09 04:26:11','2026-05-08 14:26:11','2026-05-08 20:26:11'),(11,1,1,NULL,'Backup replication lag detected','Remote storage replication delayed more than 2 hours.','in_progress','critical','2026-05-08 20:51:11','2026-05-08 13:26:11','2026-06-17 11:42:55'),(12,1,1,NULL,